Javascript.miscCode:
function DefaultCurrency223() {}
DefaultCurrency223.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency223.tabIndex = -1;
DefaultCurrency223.maxLength = 1;
DefaultCurrency223.isReadOnly = function(){return true;}
DefaultCurrency223.isTemporary = function(){return true;}
DefaultCurrency223.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency223.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }

Context.validate:
var val = Services.getValue(FeeLmtAmt.dataBinding);				
var max = 999999.99;
var err = validateCurrencyValue(val, max);

if( null == err )
{	Services.setValue(FeeLmtAmt.dataBinding, WPU.formatToTwoDP(val));
}
return err;
